2. 将每个转换后的点添加到 `cloud` 中。

下面是修改后的代码：

```cpp
#include <pcl/point_types.h>
#include <pcl/point_cloud.h>
#include <pcl/io/ply_io.h>
#include <iostream>
#include <fstream>

struct PointData {
    struct Point {
        float x, y, z;
    } point;

    unsigned char color[3];
};

// 假设 pointCloudData 是你原始的点云数据
std::vector<PointData> pointCloudData = /* your data */;

// 将数据存储到 PCL PointCloud 对象中
pcl::PointCloud<pcl::PointXYZ>::Ptr cloud(new pcl::PointCloud<pcl::PointXYZ>);

for (const auto& point : pointCloudData) {
    pcl::PointXYZ pclPoint;
    pclPoint.x = point.point.x;
    pclPoint.y = point.point.y;
    pclPoint.z = point.point.z;
    cloud->points.push_back(pclPoint);
}

cloud->width = cloud->points.size();
cloud->height = 1;
cloud->is_dense = true;

// 使用 PCL 来保存点云到 PLY 文件
if (pcl::io::savePLYFileASCII("./data/ply/demo.ply", *cloud) == 0) {
    std::cout << "Saved PointCloud : demo.ply" << std::endl;
} else {
    std::cerr << "Failed to save the point cloud to the file.\n";
}
```

