#include <pcl/point_types.h>
#include <pcl/point_cloud.h>
#include <pcl/io/ply_io.h>
#include <iostream>

int main() {
    // 定义一个 PCL PointCloud 对象，类型为 pcl::PointXYZ
    pcl::PointCloud<pcl::PointXYZ>::Ptr cloud(new pcl::PointCloud<pcl::PointXYZ>);

    // 读取PLY文件，使用PCL的loadPLYFile函数
    std::string filename("./data/ply/demo.ply");
    if (pcl::io::loadPLYFile<pcl::PointXYZ>(filename, *cloud) == -1) {
        PCL_ERROR("Couldn't read the file %s \n", filename.c_str());
        return -1;
    }

    // 输出点云中的点的数量
    std::cout << "Loaded "
              << cloud->width * cloud->height
              << " data points from " << filename << std::endl;

    // 输出点云数据（这里以5个点为例）
    for (size_t i = 0; i < std::min(cloud->points.size(), size_t(5)); ++i) {
        std::cout << " " << cloud->points[i].x
                  << " " << cloud->points[i].y
                  << " " << cloud->points[i].z << std::endl;
